using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, loops, and object-oriented principles.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00-9:50 AM", DepartmentId = 1, InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She specializes in programming language design.", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, and graphs. Algorithm analysis and design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30-11:50 AM", DepartmentId = 1, InstructorName = "Dr. Bob Martinez", InstructorBio = "Dr. Martinez researches algorithm optimization and has published over 30 papers in top computer science journals.", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", Description = "Principles of database design, SQL, normalization, and transaction management. Includes hands-on projects with relational databases.", Credits = 3, Schedule = "Mon/Wed 2:00-3:20 PM", DepartmentId = 1, InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She specializes in programming language design.", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00-10:50 AM", DepartmentId = 2, InstructorName = "Dr. Carol White", InstructorBio = "Dr. White is an award-winning educator with a passion for making mathematics accessible to all students.", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Foundation for advanced mathematics and applications.", Credits = 3, Schedule = "Tue/Thu 1:00-2:20 PM", DepartmentId = 2, InstructorName = "Dr. David Kim", InstructorBio = "Dr. Kim specializes in applied mathematics and has worked on mathematical modeling for climate science.", IsFeatured = false },
            new() { Id = 6, Title = "Discrete Mathematics", Description = "Logic, sets, relations, functions, combinatorics, and graph theory. Essential for computer science students.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00-11:50 AM", DepartmentId = 2, InstructorName = "Dr. Carol White", InstructorBio = "Dr. White is an award-winning educator with a passion for making mathematics accessible to all students.", IsFeatured = false },
            new() { Id = 7, Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to classical physics with laboratory component.", Credits = 4, Schedule = "Tue/Thu 9:00-10:20 AM + Lab Fri 2:00-4:50 PM", DepartmentId = 3, InstructorName = "Dr. Emily Johnson", InstructorBio = "Dr. Johnson is an experimental physicist whose research focuses on quantum optics and photonics.", IsFeatured = true },
            new() { Id = 8, Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, and hydrogen atom.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00-1:50 PM", DepartmentId = 3, InstructorName = "Dr. Emily Johnson", InstructorBio = "Dr. Johnson is an experimental physicist whose research focuses on quantum optics and photonics.", IsFeatured = false },
            new() { Id = 9, Title = "Creative Writing", Description = "Workshop-based course exploring fiction, poetry, and creative nonfiction. Develop your unique voice as a writer.", Credits = 3, Schedule = "Tue/Thu 3:00-4:20 PM", DepartmentId = 4, InstructorName = "Prof. Frank Rivera", InstructorBio = "Prof. Rivera is a published novelist and poet who has taught creative writing for over a decade.", IsFeatured = true },
            new() { Id = 10, Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present. Themes of identity, freedom, and society.", Credits = 3, Schedule = "Mon/Wed 10:00-11:20 AM", DepartmentId = 4, InstructorName = "Dr. Grace Park", InstructorBio = "Dr. Park specializes in 20th-century American literature and has authored two books on modernist poetry.", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(search))
        {
            query = query.Where(c => c.Title.Contains(search, StringComparison.OrdinalIgnoreCase)
                || c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));
        }

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

