@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="/courses">
    <div class="row mb-3">
        <div class="col-md-5">
            <input type="text" name="search" class="form-control" placeholder="Search courses..." value="@Search" />
        </div>
        <div class="col-md-4">
            <select name="departmentId" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in CatalogService.GetDepartments())
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-3">
            <button type="submit" class="btn btn-primary">Filter</button>
        </div>
    </div>
</form>

@{ var courses = CatalogService.GetCourses(Search, DepartmentId); }

@if (courses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Title</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td>@course.Schedule</td>
                    <td><a href="/courses/@course.Id">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p>No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
}
else
{
    <PageTitle>@course.Title</PageTitle>
    <h1>@course.Title</h1>

    <div class="mb-3">
        <span class="badge bg-primary">@course.Credits Credits</span>
        @if (department is not null)
        {
            <span class="badge bg-secondary">@department.Name</span>
        }
    </div>

    <h2>Description</h2>
    <p>@course.Description</p>

    <h2>Schedule</h2>
    <p>@course.Schedule</p>

    <h2>Instructor</h2>
    <h4>@course.InstructorName</h4>
    <p>@course.InstructorBio</p>

    <div class="mt-4">
        <a href="/enroll?courseId=@course.Id" class="btn btn-success">Enroll in This Course</a>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Back to Courses</a>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;
    private Department? department;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
        if (course is not null)
        {
            department = CatalogService.GetDepartment(course.DepartmentId);
        }
    }
}

