@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>Enroll</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Model.Name</strong>. Your enrollment request for the selected course has been received.</p>
        <a href="/courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <form method="post">
        <AntiforgeryToken />
        <div class="mb-3">
            <label for="name" class="form-label">Full Name</label>
            <input type="text" id="name" name="Model.Name" class="form-control" required value="@Model.Name" />
        </div>
        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" class="form-control" required value="@Model.StudentId" />
        </div>
        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="">-- Select a course --</option>
                @foreach (var course in CatalogService.GetCourses())
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Title</option>
                }
            </select>
        </div>
        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    private bool submitted;

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(Model.Name) && !string.IsNullOrEmpty(Model.StudentId) && Model.CourseId > 0)
        {
            CatalogService.SubmitEnrollmentRequest(Model);
            submitted = true;
        }
    }
}

